        return ListLit(items)

    def parse_dict_lit(self) -> DictLit:
        self.expect("PUNCT", "{")
        pairs = []
        if self.peek().kind != "PUNCT" or self.peek().value != "}":
            key = self.parse_expression()
            self.expect("PUNCT", ":")
