{"content":"from typing import Union, Any
from tinylang.lexer import Token, tokenize
from tinylang.ast import *
from tinylang.errors import ParseError

class Parser:
    def __init__(self, tokens: list[Token]):
        self.tokens = tokens
        self.pos = 0

    def peek(self) -> Token:
        return self.tokens[self.pos]

    def consume(self) -> Token:
        token = self.peek()
        if token.kind != "EOF":
            self.pos += 1
        return token

    def expect(self, kind: str, value: Any = None) -> Token:
        token = self.peek()
        if token.kind != kind:
            raise ParseError(f"Expected {kind}, got {token.kind}", token.line, token.col)
        if value is not None and token.value != value:
            raise ParseError(f"Expected {value}, got {token.value}", token.line, token.col)
        return self.consume()

    def parse_program(self) -> Program:
        stmts = []
        while self.peek().kind != "EOF":
            stmts.append(self.parse_statement())
        return Program(stmts)

    def parse_statement(self) -> Stmt:
        token = self.peek()
        if token.kind == "KEYWORD":
            if token.value == "let":
                return self.parse_let_stmt()
            elif token.value == "if":
                return self.parse_if_stmt()
            elif token.value == "while":
                return self.parse_while_stmt()
            elif token.value == "for":
                return self.parse_for_stmt()
            elif token.value == "fn":
                return self.parse_fn_decl()
            elif token.value == "return":
                return self.parse_return_stmt()
            elif token.value == "break":
                self.expect("KEYWORD", "break")
                self.expect("PUNCT", ";")
                return BreakStmt()
            elif token.value == "continue":
                self.expect("KEYWORD", "continue")
                self.expect("PUNCT", ";")
                return ContinueStmt()

        if token.kind == "PUNCT" and token.value == "{":
            return self.parse_block()

        # It could be an expression statement
        expr = self.parse_expression()
        if self.peek().kind == "PUNCT" and self.peek().value == ";":
            self.consume()
            return ExprStmt(expr)
        elif self.peek().kind == "EOF":
            return ExprStmt(expr)
        else:
            raise ParseError(f"Expected ';' after expression", token.line, token.col)

    def parse_let_stmt(self) -> LetStmt:
        self.expect("KEYWORD", "let")
        name_token = self.expect("IDENT")
        self.expect("PUNCT", "=")
        value = self.parse_expression()
        self.expect("PUNCT", ";")
        return LetStmt(name_token.value, value)

    def parse_if_stmt(self) -> IfStmt:
        self.expect("KEYWORD", "if")
        self.expect("PUNCT", "(")
        cond = self.parse_expression()
        self.expect("PUNCT", ")")
        then_block = self.parse_block()

        else_block = None
        if self.peek().kind == "KEYWORD" and self.peek().value == "else":
            self.consume()
            if self.peek().kind == "KEYWORD" and self.peek().value == "if":
                else_block = self.parse_if_stmt()
            else:
                else_block = self.parse_block()

        return IfStmt(cond, then_block, else_block)

    def parse_while_stmt(self) -> WhileStmt:
        self.expect("KEYWORD", "while")
        self.expect("PUNCT", "(")
        cond = self.parse_expression()
        self.expect("PUNCT", ")")
        body = self.parse_block()
        return WhileStmt(cond, body)

    def parse_for_stmt(self) -> ForStmt:
        self.expect("KEYWORD", "for")
        self.expect("PUNCT", "(")
        names = []
        names.append(self.expect("IDENT").value)
        if self.peek().kind == "PUNCT" and self.peek().value == ",":
            self.consume()
            names.append(self.expect("IDENT").value)
        self.expect("PUNCT", ")")
        self.expect("KEYWORD", "in")
        iterable = self.parse_expression()
        body = self.parse_block()
        return ForStmt(names, iterable, body)

    def parse_fn_decl(self) -> FnDecl:
        self.expect("KEYWORD", "fn")
        name = self.expect("IDENT").value
        self.expect("PUNCT", "(")
        params = []
        if self.peek().kind != "PUNCT" or self.peek().value != ")":
            params.append(self.expect("IDENT").value)
            while self.peek().kind == "PUNCT" and self.peek().value == ",":
                self.consume()
                params.append(self.expect("IDENT").value)
        self.expect("PUNCT", ")")
        body = self.parse_block()
        return FnDecl(name, params, body)

    def parse_return_stmt(self) -> ReturnStmt:
        self.expect("KEYWORD", "return")
        value = None
        if self.peek().kind != "PUNCT" or self.peek().value != ";":
            value = self.parse_expression()
        self.expect("PUNCT", ";")
        return ReturnStmt(value)

    def parse_block(self) -> Block:
        self.expect("PUNCT", "{")
        stmts = []
        while self.peek().kind != "PUNCT" or self.peek().value != "}":
            if self.peek().kind == "EOF":
                raise ParseError("Unexpected EOF in block", self.peek().line, self.peek().col)
            stmts.append(self.parse_statement())
        self.expect("PUNCT", "}")
        return Block(stmts)

    def parse_expression(self) -> Expr:
        return self.parse_assignment()

    def parse_assignment(self) -> Expr:
        expr = self.parse_logic_or()
        if self.peek().kind == "PUNCT" and self.peek().value == "=":
            self.consume()
            value = self.parse_assignment()
            if isinstance(expr, Identifier):
                return Assign(expr, value)
            elif isinstance(expr, Index):
                return Assign(expr, value)
            else:
