    def expect(self, kind: str, value: Any = None) -> Token:
        token = self.peek()
        if token.kind != kind:
            raise ParseError(f"Expected {kind}, got {token.kind}", token.line, token.col)
        if value is not None and token.value != value:
            raise ParseError(f"Expected {value}, got {token.value}", token.line, token.col)
        return self.consume()

    def parse_program(self) -> Program:
        stmts = []
        while self.peek().kind != "EOF":
            stmts.append(self.parse_statement())
        return Program(stmts)

    def parse_statement(self) -> Stmt:
        token = self.peek()
        if token.kind == "KEYWORD":
            if token.value == "let":
                return self.parse_let_stmt()
            elif token.value == "if":
                return self.parse_if_stmt()
            elif token.value == "while":
                return self.parse_while_stmt()
            elif token.value == "for":
                return self.parse_for_stmt()
            elif token.value == "fn":
                return self.parse_fn_decl()
            elif token.value == "return":
                return self.parse_return_stmt()
            elif token.value == "break":
                self.expect("KEYWORD", "break")
                self.expect("PUNCT", ";")
                return BreakStmt()
            elif token.value == "continue":
                self.expect("KEYWORD", "continue")
                self.expect("PUNCT", ";")
                return ContinueStmt()

        if token.kind == "PUNCT" and token.value == "{":
            return self.parse_block()

        # It could be an expression statement
        expr = self.parse_expression()
        if self.peek().kind == "PUNCT" and self.peek().value == ";":
            self.consume()
            return ExprStmt(expr)
        elif self.peek().kind == "EOF":
            return ExprStmt(expr)
        else:
            raise ParseError(f"Expected ';' after expression", token.line, token.col)

    def parse_let_stmt(self) -> LetStmt:
        self.expect("KEYWORD", "let")
        name_token = self.expect("IDENT")
        self.expect("PUNCT", "=")
        value = self.parse_expression()
        self.expect("PUNCT", ";")
        return LetStmt(name_token.value, value)

    def parse_if_stmt(self) -> IfStmt:
        self.expect("KEYWORD", "if")
        self.expect("PUNCT", "(")
        cond = self.parse_expression()
        self.expect("PUNCT", ")")
        then_block = self.parse_block()

        else_block = None
        if self.peek().kind == "KEYWORD" and self.peek().value == "else":
            self.consume()
            if self.peek().kind == "KEYWORD" and self.peek().value == "if":
                else_block = self.parse_if_stmt()
            else:
                else_block = self.parse_block()

